insert into public.exercises (id, name, muscle_group, equipment, target, secondary_muscles, instructions, gif_path) values
  ('db-0458', 'floor fly (with barbell)', 'Chest', 'Barbell', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Lie flat on your back on the floor with your knees bent and feet flat on the ground.','Hold a barbell with an overhand grip, arms extended straight up over your chest.','Slowly lower the barbell out to the sides, keeping a slight bend in your elbows.','Lower the barbell until your arms are parallel to the floor, feeling a stretch in your chest.','Pause for a moment, then squeeze your chest muscles to bring the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'neonEDL'),
  ('db-0459', 'flutter kicks', 'Legs', 'Body Weight', 'glutes', ARRAY['hip flexors','lower abs']::text[], ARRAY['Lie flat on your back with your legs extended and your hands by your sides.','Engage your core and lift your legs off the ground about 6 inches.','Keeping your legs straight, alternate lifting one leg slightly higher than the other.','Continue this fluttering motion for the desired number of repetitions.']::text[], 'UVo2Qs2'),
  ('db-1472', 'forward jump', 'Legs', 'Body Weight', 'quads', ARRAY['calves','hamstrings','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart.','Bend your knees and lower your body into a squat position.','Swing your arms back for momentum.','Jump forward explosively, extending your hips, knees, and ankles.','Land softly on the balls of your feet and immediately go into the next jump.','Repeat for the desired number of repetitions.']::text[], 'uZKq7lo'),
  ('db-3470', 'forward lunge (male)', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet hip-width apart and hands on your hips.','Take a big step forward with your right foot, lowering your body into a lunge position.','Bend your right knee to about 90 degrees, keeping your knee aligned with your ankle.','Push off with your right foot and return to the starting position.','Repeat with your left leg, alternating sides for the desired number of repetitions.']::text[], 'kMzUs9Y'),
  ('db-3194', 'frankenstein squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the barbell in front of your body with straight arms.','Keeping your back straight, lower your body by bending at the knees and hips, as if sitting back into a chair.','Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bdWcbaU'),
  ('db-2429', 'frog crunch', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'FFRP97T'),
  ('db-3301', 'frog planche', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','chest','triceps']::text[], ARRAY['Start in a push-up position with your hands shoulder-width apart and your feet together.','Bend your elbows and lower your body towards the ground, keeping your back straight.','As you lower your body, lift your feet off the ground and bring your knees towards your chest.','Hold this position for a few seconds, then extend your legs back out and push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'rQhGcin'),
  ('db-3296', 'front lever', 'Core', 'Body Weight', 'abs', ARRAY['lats','shoulders','forearms']::text[], ARRAY['Start by hanging from a pull-up bar with an overhand grip, hands shoulder-width apart.','Engage your core and pull your shoulder blades down and back.','Bend your knees and tuck them towards your chest.','Simultaneously, lift your legs up and extend them straight out in front of you, keeping your body parallel to the ground.','Hold this position for as long as you can, aiming for a full front lever position.','To release, slowly lower your legs back down and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'PkCN2lv'),
  ('db-3295', 'front lever reps', 'Back', 'Body Weight', 'upper back', ARRAY['core','shoulders']::text[], ARRAY['Hang from a pull-up bar with an overhand grip, palms facing away from you.','Engage your core and pull your shoulder blades down and back.','Keeping your body straight, lift your legs up until they are parallel to the ground.','Hold this position for as long as you can, aiming for 10-20 seconds.','Slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'hbY9wqG'),
  ('db-0464', 'front plank with twist', 'Core', 'Body Weight', 'abs', ARRAY['obliques','shoulders']::text[], ARRAY['Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe.','Engage your core and glutes to maintain a stable position.','Rotate your torso to the right, lifting your right arm and extending it towards the ceiling.','Keep your hips and legs stable as you twist.','Hold for a moment, then return to the starting position.','Repeat the twist on the left side.','Continue alternating sides for the desired number of repetitions.']::text[], 'CosupLu'),
  ('db-3315', 'full maltese', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','chest']::text[], ARRAY['Start by standing with your feet shoulder-width apart and your arms extended straight out to the sides.','Slowly lean forward, keeping your arms straight, until your upper body is parallel to the ground.','Engage your core and hold this position for a few seconds.','Return to the starting position by pushing through your feet and standing back up.','Repeat for the desired number of repetitions.']::text[], 'YRaCa5Y'),
  ('db-3299', 'full planche', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','chest','triceps']::text[], ARRAY['Start in a push-up position with your hands shoulder-width apart and your fingers pointing forward.','Engage your core and slowly shift your weight forward, lifting your feet off the ground.','Continue shifting your weight forward until your body is parallel to the ground, balancing on your hands.','Hold this position for as long as you can, maintaining a straight body line.','Slowly lower your feet back to the ground and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'YZ4961r'),
  ('db-3327', 'full planche push-up', 'Chest', 'Body Weight', 'pectorals', ARRAY['shoulders','triceps','core']::text[], ARRAY['Start in a push-up position with your hands placed slightly wider than shoulder-width apart.','Engage your core and lower your body down towards the ground, keeping your elbows close to your sides.','As you lower yourself, lean your body forward and lift your feet off the ground, balancing on your hands.','Continue to lower your body until your chest is just above the ground.','Push through your hands and extend your arms to lift your body back up to the starting position.','Maintain a straight line from your head to your heels throughout the movement.','Repeat for the desired number of repetitions.']::text[], 'gw9PqGk'),
  ('db-0466', 'gironda sternum chin', 'Back', 'Body Weight', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Stand facing a high bar with your feet shoulder-width apart.','Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart.','Hang from the bar with your arms fully extended and your body straight.','Engage your lats and biceps to pull your chest up towards the bar, leading with your sternum.','Pause for a moment at the top, then slowly lower yourself back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'IL0JUxR'),
  ('db-3561', 'glute bridge march', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.','While keeping your hips lifted, lift one foot off the ground and bring your knee towards your chest.','Lower your foot back to the ground and repeat the movement with the other leg.','Continue alternating legs in a marching motion while maintaining the bridge position.','Repeat for the desired number of repetitions.']::text[], 'GibBPPg'),
  ('db-3523', 'glute bridge two legs on bench (male)', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','core']::text[], ARRAY['Sit on the edge of a bench with your back against it and your feet flat on the ground.','Place your hands on the bench beside your hips for support.','Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders.','Pause for a moment at the top, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'aWedzZX'),
  ('db-3193', 'glute-ham raise', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes','lower back']::text[], ARRAY['Adjust the glute-ham raise machine to fit your body.','Position yourself face down on the machine with your ankles secured.','Place your hands on your chest or cross them over your chest.','Engage your hamstrings and glutes to lift your upper body up towards the ceiling.','Continue lifting until your body is in a straight line from your head to your heels.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Vvwjz6N'),
  ('db-0467', 'gorilla chin', 'Core', 'Body Weight', 'abs', ARRAY['forearms','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Grasp a pull-up bar with an overhand grip, slightly wider than shoulder-width apart.','Hang from the bar with your arms fully extended and your palms facing away from you.','Engage your core and pull your body up towards the bar, bringing your chin above the bar.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bmwlYvD'),
  ('db-0469', 'groin crunch', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors','inner thighs']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, lift your legs off the ground, bringing your knees towards your chest.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'mWppALS'),
  ('db-1383', 'hack calf raise', 'Legs', 'Sled Machine', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Adjust the sled machine to a comfortable weight.','Stand on the sled machine with your toes on the platform and your heels hanging off.','Hold onto the handles for stability.','Raise your heels as high as possible by pushing through the balls of your feet.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '2ORFMoR'),
  ('db-1384', 'hack one leg calf raise', 'Legs', 'Sled Machine', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Adjust the sled machine to an appropriate weight.','Stand on the sled machine with one foot, keeping the other foot off the ground.','Hold onto the handles for stability.','Raise your heel as high as possible, lifting your body up on the ball of your foot.','Pause for a moment at the top, then slowly lower your heel back down to the starting position.','Repeat for the desired number of repetitions.','Switch legs and repeat the exercise.']::text[], 'AxFoqAD'),
  ('db-3221', 'half knee bends (male)', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart.','Bend your knees and lower your body down as if you were sitting back into a chair.','Keep your chest up and your weight in your heels.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ia6kIIl'),
  ('db-3202', 'half sit-up (male)', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'iQ241UP'),
  ('db-1511', 'hamstring stretch', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes']::text[], ARRAY['Stand with your feet shoulder-width apart.','Step forward with your right foot and shift your weight onto your right leg.','Keeping your back straight, slowly bend forward at the hips, reaching towards your right foot with both hands.','Hold the stretch for 20-30 seconds, then return to the starting position.','Repeat on the other side.']::text[], '99rWm7w'),
  ('db-2139', 'hands bike', 'Chest', 'Upper Body Ergometer', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the seat height and handlebar position to a comfortable level.','Sit on the ergometer with your back straight and feet on the pedals.','Grasp the handles with your hands and position your arms at a 90-degree angle.','Start pedaling with your hands, pushing and pulling the handles in a controlled motion.','Continue pedaling for the desired duration or number of repetitions.']::text[], 'pAIWRGu'),
  ('db-3218', 'hands clasped circular toe touch (male)', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','quadriceps','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and your hands clasped together in front of your chest.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Lower your hands towards your toes in a circular motion, reaching as far as you can without straining.','Pause for a moment at the bottom, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'B5xca8s'),
  ('db-3215', 'hands reversed clasped circular toe touch (male)', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','quadriceps','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and your arms extended to the sides.','Bend forward at the waist, keeping your back straight and your knees slightly bent.','Reach down with your hands and clasp them together behind your legs.','Slowly raise your hands up and over your head in a circular motion, keeping your legs straight.','Continue the circular motion until your hands touch your toes.','Reverse the motion and bring your hands back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'yq3GAJX'),
  ('db-3302', 'handstand', 'Arms', 'Body Weight', 'triceps', ARRAY['shoulders','core']::text[], ARRAY['Find an open space with enough room to perform a handstand.','Place your hands on the ground shoulder-width apart, fingers pointing forward.','Kick your legs up towards the wall, using your core and shoulders to maintain balance.','Once in a handstand position, engage your triceps to support your body weight.','Hold the handstand for as long as you can maintain balance.','To come down, slowly lower your legs back to the ground.','Repeat for the desired number of repetitions.']::text[], 'XooAdhl'),
  ('db-0471', 'handstand push-up', 'Arms', 'Body Weight', 'triceps', ARRAY['shoulders','chest','core']::text[], ARRAY['Find a wall and face away from it, standing a few feet away.','Place your hands on the ground shoulder-width apart and kick your feet up against the wall, coming into a handstand position.','Bend your elbows and lower your head towards the ground, keeping your body in a straight line.','Push through your hands and extend your arms to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'rQxwMxO'),
  ('db-1764', 'hanging leg hip raise', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.','Engage your core and lift your legs up by flexing your hips and knees until your thighs are parallel to the ground.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'VEcJRo2'),
  ('db-0472', 'hanging leg raise', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.','Engage your core and lift your legs up in front of you, keeping them straight.','Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'I3tsCnC'),
  ('db-1761', 'hanging oblique knee raise', 'Core', 'Body Weight', 'abs', ARRAY['obliques']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.','Engage your core and lift your knees towards your chest, twisting your torso to the side as you do so.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat on the other side, twisting your torso in the opposite direction.','Continue alternating sides for the desired number of repetitions.']::text[], 'BaE7O6U'),
  ('db-0473', 'hanging pike', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors','shoulders']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.','Engage your core and lift your legs up towards the bar, keeping them straight.','Continue lifting until your body forms a ''V'' shape, with your legs parallel to the ground.','Hold the position for a moment, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'nuBF9MO'),
  ('db-0474', 'hanging straight leg hip raise', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.','Engage your core and lift your legs up in front of you until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'pj0X0tF'),
  ('db-0475', 'hanging straight leg raise', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.','Engage your core and lift your legs up in front of you, keeping them straight.','Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '4Ml7QFO'),
  ('db-0476', 'hanging straight twisting leg hip raise', 'Core', 'Body Weight', 'abs', ARRAY['obliques','hip flexors']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your legs straight.','Engage your core and lift your legs up towards your chest, keeping them straight.','Once your legs are parallel to the ground, twist your hips to one side, bringing your legs towards that side.','Pause for a moment, then return to the starting position.','Repeat the movement, but this time twist your hips to the opposite side.','Continue alternating sides for the desired number of repetitions.']::text[], 'Q6bvyen'),
  ('db-3636', 'high knee against wall', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','glutes','calves']::text[], ARRAY['Stand facing a wall with your feet hip-width apart.','Place your hands on the wall for support.','Engage your core and lift your right knee up towards your chest, while keeping your left foot on the ground.','Quickly switch legs, bringing your left knee up towards your chest and lowering your right foot back down.','Continue alternating legs in a running motion, bringing your knees up as high as possible.','Maintain a fast pace and keep your upper body stable throughout the exercise.','Repeat for the desired duration or number of repetitions.']::text[], 'ealLwvX'),
  ('db-0484', 'hip raise (bent knee)', 'Core', 'Body Weight', 'abs', ARRAY['glutes','hamstrings']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands by your sides, palms facing down.','Engage your core and glutes, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.','Pause for a moment at the top, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '196HJGw'),
  ('db-1418', 'hug keens to chest', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Start by standing with your feet shoulder-width apart.','Bend your knees and lower your body down into a squat position.','As you squat down, bring your knees up towards your chest and hug them with your arms.','Hold this position for a moment, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'znP9SIh'),
  ('db-3234', 'hyght dumbbell fly', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing each other.','Extend your arms straight up over your chest, with a slight bend in your elbows.','Keeping a slight bend in your elbows, lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.','Pause for a moment, then reverse the movement and bring the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'P9ZRyLT'),
  ('db-0489', 'hyperextension', 'Back', 'Body Weight', 'spine', ARRAY['glutes','hamstrings']::text[], ARRAY['Adjust the hyperextension bench so that your upper thighs are resting on the pad and your feet are secured.','Cross your arms over your chest or place your hands behind your head.','Lower your upper body towards the ground while keeping your back straight.','Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs.','Repeat for the desired number of repetitions.']::text[], 'zhMwOwE'),
  ('db-0488', 'hyperextension (on bench)', 'Back', 'Body Weight', 'spine', ARRAY['glutes','hamstrings']::text[], ARRAY['Adjust the hyperextension bench so that your hips are resting comfortably on the pad and your feet are secured.','Cross your arms over your chest or place your hands behind your head.','Slowly lower your upper body towards the ground while keeping your back straight.','Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs.','Repeat for the desired number of repetitions.']::text[], 'zkgRrbK'),
  ('db-3289', 'impossible dips', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Position yourself between two parallel bars with your arms fully extended and your body suspended in the air.','Bend your knees and cross your ankles.','Lower your body by bending your elbows until your upper arms are parallel to the ground.','Pause for a moment, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], '05Cf2v8'),
  ('db-1471', 'inchworm', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','hamstrings']::text[], ARRAY['Start in a standing position with your feet hip-width apart.','Bend forward at the waist and place your hands on the ground in front of you.','Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe.','Pause for a moment, then walk your hands back towards your feet, keeping your legs as straight as possible.','Once your hands reach your feet, stand back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZgsNQ6d'),
  ('db-3698', 'inchworm v. 2', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','hamstrings']::text[], ARRAY['Start in a standing position with your feet hip-width apart.','Bend forward at the waist and place your hands on the ground in front of you.','Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe.','Keeping your legs straight, walk your feet towards your hands, bringing your hips up towards the ceiling.','Continue walking your hands forward, repeating the movement for the desired number of repetitions.']::text[], 'TV87DNB'),
  ('db-0490', 'incline close-grip push-up', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart.','Extend your legs behind you, resting on the balls of your feet, with your body forming a straight line from head to heels.','Lower your chest towards the elevated surface by bending your elbows, keeping them close to your sides.','Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], '1YB40kg'),
  ('db-0491', 'incline leg hip raise (leg straight)', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie on an incline bench with your back flat against the bench and your legs extended straight out in front of you.','Place your hands on the sides of the bench for support.','Engaging your abs, lift your legs off the bench, raising them as high as you can while keeping them straight.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'eVxAzgz'),
  ('db-0492', 'incline push up depth jump', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Find an elevated surface, such as a bench or step, and place your hands shoulder-width apart on the edge.','Step your feet back, keeping your body in a straight line from head to heels.','Lower your chest towards the edge of the surface, bending your elbows and keeping your body aligned.','Push through your palms to extend your arms and return to the starting position.','Jump off the edge of the surface, landing softly with your knees slightly bent.','Repeat the push-up and depth jump for the desired number of repetitions.']::text[], 'CB8WET1'),
  ('db-0493', 'incline push-up', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart.','Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.','Lower your chest towards the elevated surface by bending your elbows, keeping your body in a straight line.','Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'B1EVP9F'),
  ('db-3785', 'incline push-up (on box)', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Place your hands on the edge of a box or elevated surface, slightly wider than shoulder-width apart.','Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.','Lower your chest towards the box by bending your elbows, keeping your body in a straight line.','Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'F7vjXqT'),
  ('db-0494', 'incline reverse grip push-up', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Place your hands on the edge of a bench or elevated surface, slightly wider than shoulder-width apart.','Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.','Lower your chest towards the bench by bending your elbows, keeping them close to your sides.','Pause for a moment at the bottom, then push yourself back up to the starting position by extending your arms.','Repeat for the desired number of repetitions.']::text[], 'XaaRnRn'),
  ('db-3011', 'incline scapula push up', 'Chest', 'Body Weight', 'serratus anterior', ARRAY['triceps','shoulders']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Place your hands on the bench slightly wider than shoulder-width apart.','Position your feet on the ground, hip-width apart.','Lower your chest towards the bench, keeping your elbows tucked in.','As you lower, retract your shoulder blades, squeezing your scapulae together.','Push through your palms to extend your arms and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'GdMa1ET'),
  ('db-0495', 'incline twisting sit-up', 'Core', 'Body Weight', 'abs', ARRAY['obliques']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Lie down on the bench with your feet secured under the foot pads.','Place your hands behind your head or across your chest.','Engage your abs and lift your upper body off the bench, curling forward.','As you curl up, twist your torso to one side, bringing your elbow towards the opposite knee.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat the movement, this time twisting your torso to the other side.','Continue alternating sides for the desired number of repetitions.']::text[], '9ZGZuOD'),
  ('db-1564', 'intermediate hip flexor and quad stretch', 'Legs', 'Rope', 'quads', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand upright with your feet shoulder-width apart.','Hold onto a stable object for support.','Bend your right knee and bring your right foot towards your glutes, grabbing the rope with your right hand.','Slowly pull your right foot towards your glutes, feeling a stretch in your right quad.','Hold the stretch for 20-30 seconds.','Release the stretch and repeat on the left side.']::text[], 'tFGKm99'),
  ('db-0496', 'inverse leg curl (bench support)', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes','calves']::text[], ARRAY['Lie face down on a bench with your hips at the edge and your legs extended straight behind you.','Hold onto the bench for support.','Keeping your upper body still, bend your knees and curl your legs towards your glutes.','Pause for a moment at the top, then slowly extend your legs back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ms7tjSG'),
  ('db-2400', 'inverse leg curl (on pull-up cable machine)', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes','calves']::text[], ARRAY['Adjust the cable machine so that the ankle straps are at the lowest setting.','Lie face down on the bench with your legs extended and the ankle straps attached to your feet.','Hold onto the handles of the bench for stability.','Bend your knees and curl your legs towards your glutes, squeezing your hamstrings.','Pause for a moment at the top of the movement, then slowly lower your legs back to the starting position.','Repeat for the desired number of repetitions.']::text[], '0rHfvy9'),
  ('db-0499', 'inverted row', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Set up a bar at waist height or use a suspension trainer.','Stand facing the bar or suspension trainer, with your feet shoulder-width apart.','Grab the bar or handles with an overhand grip, slightly wider than shoulder-width apart.','Lean back, keeping your body straight and your heels on the ground.','Pull your chest towards the bar or handles, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower yourself back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bZGHsAZ'),
  ('db-2300', 'inverted row bent knees', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Set up a bar at waist height and lie underneath it.','Grab the bar with an overhand grip, slightly wider than shoulder-width apart.','Position your body so that your heels are on the ground and your body is straight.','Pull your chest up towards the bar by squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'VPPtusI'),
  ('db-2298', 'inverted row on bench', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Set up a bench at a height that allows your body to hang freely underneath it.','Lie face up on the ground with your head towards the bench.','Reach up and grab the bench with an overhand grip, slightly wider than shoulder-width apart.','Position your body so that your heels are on the ground and your arms are fully extended.','Engage your core and squeeze your shoulder blades together as you pull your chest up towards the bench.','Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Mxa7Cr8'),
  ('db-0497', 'inverted row v. 2', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Set up a bar at waist height on a Smith machine or use a suspension trainer.','Stand facing the bar or suspension trainer and grab it with an overhand grip, hands shoulder-width apart.','Walk your feet forward, leaning back until your body is at a slight angle.','Keep your body straight and pull your chest up towards the bar or handles, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower yourself back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'uX3sUBz'),
  ('db-0498', 'inverted row with straps', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Set up a suspension trainer or straps at chest height.','Stand facing the anchor point and grab the handles with an overhand grip.','Walk your feet forward, leaning back until your body is at an angle.','Keep your body straight and engage your core.','Pull your chest towards the handles, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower yourself back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'jdiExfW'),
  ('db-1419', 'iron cross stretch', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Lie flat on your back with your arms extended out to the sides.','Raise your legs up towards the ceiling, keeping them straight.','Slowly lower your legs to one side, aiming to touch the floor with your feet.','Hold the stretch for a few seconds, then return your legs to the starting position.','Repeat the stretch on the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'pZwUsKB'),
  ('db-1297', 'isometric chest squeeze', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Extend your arms straight out in front of you, parallel to the ground, with your palms facing each other.','Squeeze your chest muscles together as hard as you can, while keeping your arms straight.','Hold this position for a few seconds, focusing on contracting your chest muscles.','Release the squeeze and relax your chest muscles.','Repeat for the desired number of repetitions.']::text[], 'HbSG1Pw'),
  ('db-0500', 'isometric wipers', 'Chest', 'Body Weight', 'pectorals', ARRAY['shoulders','triceps','core']::text[], ARRAY['Start by lying flat on your back on a mat or bench.','Extend your arms straight out to the sides, perpendicular to your body.','Engage your core and lift both legs off the ground, keeping them together and straight.','Slowly lower your legs to one side, aiming to touch the ground with your feet while maintaining control.','Pause for a moment, then use your core to lift your legs back to the starting position.','Repeat the movement, this time lowering your legs to the opposite side.','Continue alternating sides for the desired number of repetitions.']::text[], '11wrviz'),
  ('db-0501', 'jack burpee', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves','shoulders','triceps','core']::text[], ARRAY['Start in a standing position with your feet shoulder-width apart.','Lower your body into a squat position, placing your hands on the ground in front of you.','Kick your feet back, landing in a push-up position.','Perform a push-up, lowering your chest to the ground and then pushing back up.','Jump your feet forward, landing in a squat position.','Jump up explosively, reaching your arms overhead.','Land softly and immediately lower back into the squat position to begin the next repetition.']::text[], 'mr7pkqP'),
  ('db-3224', 'jack jump (male)', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','calves']::text[], ARRAY['Stand with your feet together and your arms by your sides.','Jump up, spreading your feet apart and raising your arms above your head.','As you land, quickly jump back to the starting position.','Repeat for the desired number of repetitions.']::text[], '1g5bPpA'),
  ('db-0507', 'jackknife sit-up', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your legs extended and your arms overhead.','Engage your core and lift your legs and upper body simultaneously, reaching your hands towards your toes.','Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'mbkgB44'),
  ('db-0508', 'janda sit-up', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '1GPHRyK'),
  ('db-2612', 'jump rope', 'Other', 'Rope', 'cardiovascular system', ARRAY['calves','quadriceps','hamstrings','glutes']::text[], ARRAY['Hold the handles of the jump rope with your hands, palms facing inward.','Stand with your feet shoulder-width apart and knees slightly bent.','Swing the rope over your head and jump over it as it comes towards your feet.','Land softly on the balls of your feet and repeat the jump as the rope comes around again.','Continue jumping for the desired duration or number of repetitions.']::text[], 'e1e76I2'),
  ('db-0514', 'jump squat', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Lower your body into a squat position by bending your knees and pushing your hips back.','Jump explosively off the ground, extending your hips, knees, and ankles.','While in mid-air, quickly bring your arms forward for balance.','Land softly on the balls of your feet and immediately go into the next repetition.','Repeat for the desired number of repetitions.']::text[], 'LIlE5Tn'),
  ('db-0513', 'jump squat v. 2', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Lower your body into a squat position by bending your knees and pushing your hips back.','Jump explosively, extending your hips and knees fully.','Land softly on the balls of your feet and immediately lower your body back into a squat position.','Repeat for the desired number of repetitions.']::text[], 'TDYiji6'),
  ('db-0517', 'kettlebell advanced windmill', 'Core', 'Kettlebell', 'abs', ARRAY['obliques','shoulders']::text[], ARRAY['Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.','Hold a kettlebell in your right hand, with your arm extended overhead and your palm facing forward.','Rotate your left foot slightly to the right, and shift your weight onto your left leg.','Bend your left knee and hinge at the hip, lowering your torso towards the left side.','Keep your right arm extended overhead and your eyes on the kettlebell.','As you lower your torso, allow your right leg to straighten and your right foot to pivot slightly.','Lower your torso until you feel a stretch in your left hamstring and your right arm is pointing towards the ground.','Pause for a moment, then engage your core and push through your left heel to return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'Kal9cQQ'),
  ('db-0518', 'kettlebell alternating hang clean', 'Arms', 'Kettlebell', 'forearms', ARRAY['shoulders','traps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in each hand with an overhand grip.','Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.','Allow the kettlebells to hang in front of your body with your arms fully extended.','In one fluid motion, explosively extend your hips, shrug your shoulders, and pull the kettlebells up towards your shoulders.','As the kettlebells reach shoulder height, rotate your wrists and catch the kettlebells in the rack position, with your palms facing inward and the kettlebells resting on the outside of your forearms.','Lower the kettlebells back down to the starting position and repeat the movement with the opposite arm.','Continue alternating arms for the desired number of repetitions.']::text[], 'I4tibZG'),
  ('db-0520', 'kettlebell alternating press', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.','Press one kettlebell overhead, fully extending your arm.','Lower the kettlebell back to shoulder height.','Repeat with the other arm.','Continue alternating arms for the desired number of repetitions.']::text[], '5KLbZWx'),
  ('db-0519', 'kettlebell alternating press on floor', 'Chest', 'Kettlebell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Start by lying on your back on the floor with your knees bent and feet flat on the ground.','Hold a kettlebell in each hand, with your palms facing towards your feet and your arms extended straight up towards the ceiling.','Lower one kettlebell down towards your shoulder while keeping the other kettlebell extended straight up.','Press the lowered kettlebell back up to the starting position while simultaneously lowering the other kettlebell down towards your shoulder.','Continue alternating the press motion with each kettlebell for the desired number of repetitions.']::text[], '7w6i0vE'),
  ('db-0521', 'kettlebell alternating renegade row', 'Back', 'Kettlebell', 'upper back', ARRAY['core','shoulders']::text[], ARRAY['Start in a high plank position with your hands gripping the kettlebells and your feet hip-width apart.','Engage your core and keep your body in a straight line from head to heels.','Pull one kettlebell up towards your chest, keeping your elbow close to your body.','Lower the kettlebell back down to the starting position and repeat with the other arm.','Continue alternating arms for the desired number of repetitions.']::text[], 'b9kqlBy'),
  ('db-0522', 'kettlebell alternating row', 'Back', 'Kettlebell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body.','Bend forward at the hips, keeping your back straight and your core engaged.','Pull one kettlebell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.','Lower the kettlebell back down to the starting position and repeat with the other arm.','Continue alternating arms for the desired number of repetitions.']::text[], 'Ca76jUE'),
  ('db-0523', 'kettlebell arnold press', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height with your palms facing towards you.','Engage your core and press the kettlebells overhead, rotating your palms to face forward as you extend your arms.','Pause at the top of the movement, then slowly lower the kettlebells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'UM8mgyG'),
  ('db-0524', 'kettlebell bent press', 'Core', 'Kettlebell', 'abs', ARRAY['shoulders','triceps','obliques']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in your right hand.','Bend your knees slightly and press the kettlebell overhead with your right arm, keeping your elbow locked.','Rotate your torso to the left, shifting your weight onto your left foot.','Bend your left knee and lower your torso towards the ground, keeping your right arm extended overhead.','As you lower, keep your eyes on the kettlebell and your chest lifted.','Once your left hand touches the ground, push through your left foot and straighten your left leg, driving your hips forward.','As you drive your hips forward, use your core and right arm to press the kettlebell back up to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'kjE55n5'),
  ('db-0525', 'kettlebell bottoms up clean from the hang position', 'Arms', 'Kettlebell', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip.','Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.','Allow the kettlebell to hang down between your legs, with your arm fully extended.','In one fluid motion, explosively extend your hips and knees while pulling the kettlebell up towards your shoulder.','As the kettlebell reaches shoulder height, rotate your wrist so that the bottom of the kettlebell is facing up.','Catch the kettlebell at shoulder height with your elbow bent and your palm facing up.','Lower the kettlebell back down to the starting position by reversing the movement.','Repeat for the desired number of repetitions, then switch sides.']::text[], '4KJEpzb'),
  ('db-0526', 'kettlebell double alternating hang clean', 'Arms', 'Kettlebell', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in each hand with an overhand grip.','Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.','Allow the kettlebells to hang straight down in front of your body.','In one fluid motion, explosively extend your hips and knees while shrugging your shoulders.','As the kettlebells rise, pull them up towards your shoulders, keeping your elbows high and out to the sides.','Catch the kettlebells at shoulder height, with your palms facing inward and your elbows pointing forward.','Lower the kettlebells back down to the starting position and repeat for the desired number of repetitions.']::text[], 'a4F9Oyc'),
  ('db-0527', 'kettlebell double jerk', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.','Bend your knees slightly and engage your core.','Press the kettlebells overhead, fully extending your arms.','Bend your knees and quickly drop into a partial squat.','Explosively extend your hips and knees, driving the kettlebells overhead.','Lock out your arms and catch the kettlebells overhead with your knees slightly bent.','Stand up straight and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'tznL2Ad'),
  ('db-0528', 'kettlebell double push press', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Start by standing with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.','Bend your knees slightly and engage your core.','Initiate the movement by explosively extending your hips, knees, and ankles, driving the kettlebells overhead.','As the kettlebells reach the top, press them fully overhead, locking out your arms.','Lower the kettlebells back to the starting position by bending your elbows and bringing them back down to shoulder height.','Repeat for the desired number of repetitions.']::text[], 'I4KkPdl'),
  ('db-0529', 'kettlebell double snatch', 'Shoulders', 'Kettlebell', 'delts', ARRAY['trapezius','forearms','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in each hand at arm''s length in front of your thighs.','Bend your knees slightly and hinge forward at the hips, keeping your back flat and chest up.','In one explosive motion, extend your hips, knees, and ankles, and simultaneously pull the kettlebells up towards your shoulders.','As the kettlebells reach shoulder level, rotate your wrists and punch the kettlebells overhead, fully extending your arms.','Lower the kettlebells back down to the starting position and repeat for the desired number of repetitions.']::text[], 'M74kdvm'),
  ('db-0530', 'kettlebell double windmill', 'Core', 'Kettlebell', 'abs', ARRAY['shoulders','hamstrings']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in your right hand.','Extend your right arm overhead, keeping your eyes on the kettlebell.','Rotate your left foot 45 degrees to the left and your right foot 90 degrees to the right.','Bend at the waist to the left, keeping your right arm extended overhead.','Lower the kettlebell towards the ground, reaching towards your left foot.','Pause for a moment, then engage your core and push through your right foot to return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'OaE7CpD'),
  ('db-0531', 'kettlebell extended range one arm press on floor', 'Chest', 'Kettlebell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Start by lying on your back on the floor with your knees bent and feet flat on the ground.','Hold a kettlebell in one hand, with your palm facing towards your feet.','Extend your arm straight up towards the ceiling, keeping your elbow locked and your wrist straight.','Slowly lower the kettlebell back down to the starting position, maintaining control throughout the movement.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'rseLfH3'),
  ('db-0532', 'kettlebell figure 8', 'Core', 'Kettlebell', 'abs', ARRAY['shoulders','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in one hand.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Pass the kettlebell between your legs, switching hands as it reaches the back of your legs.','As the kettlebell comes forward, pass it to the other hand between your legs.','Continue passing the kettlebell between your legs in a figure 8 motion.','Maintain a steady pace and engage your core throughout the exercise.','Repeat for the desired number of repetitions.']::text[], 'L4ay0PW'),
  ('db-0533', 'kettlebell front squat', 'Legs', 'Kettlebell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, toes slightly turned out.','Hold the kettlebell with both hands in front of your chest, close to your body.','Engage your core and keep your chest up as you lower your hips down and back, as if sitting into a chair.','Lower until your thighs are parallel to the ground, or as low as you can comfortably go.','Drive through your heels to stand back up, squeezing your glutes at the top.','Repeat for the desired number of repetitions.']::text[], 'DB0n8AG'),
  ('db-0534', 'kettlebell goblet squat', 'Legs', 'Kettlebell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell close to your chest with both hands.','Keeping your chest up and core engaged, lower your body down into a squat position by bending at the knees and hips.','Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZA8b5hc'),
  ('db-0535', 'kettlebell hang clean', 'Legs', 'Kettlebell', 'hamstrings', ARRAY['glutes','quadriceps','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in front of your thighs.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Lower the kettlebell towards the ground, allowing it to swing between your legs.','Quickly extend your hips and knees, using the momentum to swing the kettlebell up to shoulder height.','As the kettlebell reaches shoulder height, rotate your wrists and catch the kettlebell in the rack position, with your elbow tucked in and the kettlebell resting on your forearm.','Lower the kettlebell back down to the starting position between your legs, and repeat for the desired number of repetitions.']::text[], 'LHWF7us'),
  ('db-0536', 'kettlebell lunge pass through', 'Legs', 'Kettlebell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands.','Take a step forward with your right foot, lowering your body into a lunge position.','As you lunge forward, pass the kettlebell under your right thigh and transfer it to your left hand.','Push off with your right foot to return to the starting position, while simultaneously passing the kettlebell back to your right hand.','Repeat the lunge on the opposite side, passing the kettlebell under your left thigh.','Continue alternating lunges and passing the kettlebell between hands for the desired number of repetitions.']::text[], 'WKMQzCD'),
  ('db-0537', 'kettlebell one arm clean and jerk', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip.','Bend your knees slightly and hinge at the hips, lowering the kettlebell between your legs.','Explosively extend your hips, knees, and ankles, using the momentum to swing the kettlebell up to shoulder height.','As the kettlebell reaches shoulder height, rotate your wrist and punch your hand straight up, locking out your arm overhead.','Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions.']::text[], 'vzAxBtt'),
  ('db-1298', 'kettlebell one arm floor press', 'Chest', 'Kettlebell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie flat on your back on the floor with your knees bent and feet flat on the ground.','Hold the kettlebell in one hand with your palm facing towards your feet and your arm extended straight up towards the ceiling.','Slowly lower the kettlebell towards your chest by bending your elbow, keeping your upper arm close to your body.','Pause for a moment when the kettlebell is just above your chest, then push it back up to the starting position by extending your elbow.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'rg59QCH'),
  ('db-0538', 'kettlebell one arm jerk', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder height.','Bend your knees slightly and engage your core.','Press the kettlebell overhead in a straight line, fully extending your arm.','As you press the kettlebell overhead, simultaneously dip your knees and quickly straighten them to generate momentum.','As the kettlebell reaches its highest point, quickly drop underneath it by bending your knees and hips.','Catch the kettlebell with a slight bend in your knees and hips, and your arm fully extended overhead.','Stand up straight, fully extending your knees and hips, and stabilize the kettlebell overhead.','Lower the kettlebell back to the starting position by bending your knees and hips, and repeat for the desired number of repetitions.']::text[], 'S37C94C'),
  ('db-0539', 'kettlebell one arm military press to the side', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder height.','Engage your core and keep your back straight.','Press the kettlebell overhead, extending your arm fully.','Pause for a moment at the top, then slowly lower the kettlebell back to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'yCvYdi7'),
  ('db-0540', 'kettlebell one arm push press', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder level.','Bend your knees slightly and engage your core.','Press the kettlebell overhead by extending your arm and fully extending your legs.','Lower the kettlebell back to the starting position by bending your knees and bringing the kettlebell back to your shoulder.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'osdXT3K'),
  ('db-0541', 'kettlebell one arm row', 'Back', 'Kettlebell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip.','Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.','Pull the kettlebell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the kettlebell back down to the starting position.','Repeat for the desired number of repetitions, then switch sides and repeat with the other arm.']::text[], 'g9AsZ8P'),
  ('db-0542', 'kettlebell one arm snatch', 'Shoulders', 'Kettlebell', 'delts', ARRAY['trapezius','forearms','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in one hand between your legs.','Bend your knees slightly and hinge at the hips, lowering the kettlebell towards the ground.','Explosively extend your hips and knees, using the momentum to swing the kettlebell up towards your shoulder.','As the kettlebell reaches shoulder height, rotate your hand and punch it straight up overhead, fully extending your arm.','Lower the kettlebell back down between your legs and repeat for the desired number of repetitions.']::text[], 'aXcUyKb'),
  ('db-0543', 'kettlebell pirate supper legs', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in one hand.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Raise the kettlebell up to shoulder height, keeping your elbow close to your body.','Extend your arm fully overhead, straightening your elbow.','Lower the kettlebell back down to shoulder height, then return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'kuXhl0o'),
  ('db-0544', 'kettlebell pistol squat', 'Legs', 'Kettlebell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands.','Lift your left foot off the ground and extend it forward, keeping it parallel to the ground.','Slowly lower your body down into a squat position, keeping your right foot flat on the ground and your left leg extended.','Pause for a moment at the bottom of the squat, then push through your right heel to return to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], '5bpPTHv'),
  ('db-0545', 'kettlebell plyo push-up', 'Chest', 'Kettlebell', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Start in a high plank position with your hands on the kettlebells, shoulder-width apart.','Lower your chest towards the ground, keeping your elbows close to your body.','Push through your hands explosively, lifting your hands off the kettlebells and extending your arms fully.','Land softly back on the kettlebells and immediately lower your chest back down for the next repetition.','Repeat for the desired number of repetitions.']::text[], 'ktf3nvW'),
  ('db-0546', 'kettlebell seated press', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a kettlebell in each hand at shoulder height, palms facing forward.','Press the kettlebells overhead, fully extending your arms.','Lower the kettlebells back to shoulder height.','Repeat for the desired number of repetitions.']::text[], 'BkxB8LW'),
  ('db-1438', 'kettlebell seated two arm military press', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Sit on a bench with your back straight and feet flat on the ground.','Hold a kettlebell in each hand at shoulder level with your palms facing forward.','Press the kettlebells overhead by extending your arms fully.','Pause for a moment at the top, then slowly lower the kettlebells back to shoulder level.','Repeat for the desired number of repetitions.']::text[], 'ZEkjZDi'),
  ('db-0547', 'kettlebell seesaw press', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.','Press one kettlebell overhead while keeping the other kettlebell at shoulder height.','Lower the pressed kettlebell back to shoulder height while simultaneously pressing the other kettlebell overhead.','Continue alternating the pressing motion, creating a seesaw-like movement.','Repeat for the desired number of repetitions.']::text[], 'UDm6cGl'),
  ('db-0548', 'kettlebell sumo high pull', 'Back', 'Kettlebell', 'traps', ARRAY['shoulders','glutes','hamstrings']::text[], ARRAY['Stand with your feet wider than shoulder-width apart, toes pointing outwards.','Hold a kettlebell with both hands in front of your body, arms extended downwards.','Bend your knees and lower your hips into a squat position, keeping your back straight.','Drive through your heels and explosively extend your hips and knees, pulling the kettlebell up towards your chin.','As you pull the kettlebell up, keep your elbows high and wide, and squeeze your shoulder blades together.','Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions.']::text[], '8ARQ9Hw'),
  ('db-0549', 'kettlebell swing', 'Legs', 'Kettlebell', 'glutes', ARRAY['hamstrings','core']::text[], ARRAY['Stand with your feet shoulder-width apart, toes pointed slightly outward.','Hold the kettlebell with both hands in front of your body, arms extended.','Bend your knees slightly and hinge at the hips, pushing your butt back.','Swing the kettlebell back between your legs, keeping your arms straight and maintaining a flat back.','Drive your hips forward and swing the kettlebell up to shoulder height, using the momentum generated by your hips.','Allow the kettlebell to swing back down between your legs and repeat the movement for the desired number of repetitions.']::text[], 'UHJlbu3'),
  ('db-0550', 'kettlebell thruster', 'Shoulders', 'Kettlebell', 'delts', ARRAY['quadriceps','glutes','core']::text[], ARRAY['Start by standing with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands, palms facing each other.','Lower into a squat position by bending your knees and pushing your hips back, keeping your chest up and your back straight.','As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the kettlebell overhead.','Lock out your arms at the top of the movement, fully extending your elbows.','Lower the kettlebell back to the starting position by reversing the movement, bending your elbows and lowering the weight back to your chest.','Repeat for the desired number of repetitions.']::text[], 'yWxMvB5'),
  ('db-0551', 'kettlebell turkish get up (squat style)', 'Legs', 'Kettlebell', 'glutes', ARRAY['quadriceps','hamstrings','core']::text[], ARRAY['Start by lying on your back with your legs extended and the kettlebell held in your right hand, arm fully extended above your shoulder.','Bend your right knee and place your right foot flat on the ground, keeping your left leg extended.','Pressing through your right foot, lift your hips off the ground, coming into a bridge position.','Slide your left leg underneath your body, bending your left knee and placing your left foot flat on the ground.','Rotate your torso to the left, bringing your left hand to the ground for support.','Pressing through your right foot and left hand, lift your torso off the ground, coming into a kneeling position.','From the kneeling position, stand up, keeping the kettlebell extended overhead.','Reverse the movement to return to the starting position.','Repeat the exercise on the other side, starting with the kettlebell in your left hand.']::text[], 'Ha7SZ3y'),
  ('db-0552', 'kettlebell two arm clean', 'Shoulders', 'Kettlebell', 'delts', ARRAY['traps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in front of your thighs with both hands, palms facing towards you.','Bend your knees slightly and hinge at the hips, lowering the kettlebell towards the ground.','Explosively extend your hips and knees, using the momentum to pull the kettlebell up towards your shoulders.','As the kettlebell reaches shoulder height, rotate your wrists and catch the kettlebell in the rack position, with your elbows tucked in and the kettlebell resting on the back of your forearm.','Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions.']::text[], '7Ba7bQ2'),
  ('db-0553', 'kettlebell two arm military press', 'Shoulders', 'Kettlebell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder level with your palms facing forward.','Engage your core and press the kettlebells overhead, fully extending your arms.','Pause for a moment at the top, then slowly lower the kettlebells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'blBXysN'),
  ('db-1345', 'kettlebell two arm row', 'Back', 'Kettlebell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body.','Bend forward at the hips, keeping your back straight and your core engaged.','Pull the kettlebells up towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the kettlebells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'wf24o8S'),
  ('db-0554', 'kettlebell windmill', 'Core', 'Kettlebell', 'abs', ARRAY['obliques','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a kettlebell in your right hand overhead.','Rotate your left foot outwards about 45 degrees and keep your right foot pointing forward.','Bend your torso to the left side, keeping your right arm extended overhead and your eyes on the kettlebell.','Lower your torso as far as you can while keeping your right arm straight and your left arm extended to the side.','Pause for a moment, then return to the starting position by pushing through your right foot and engaging your obliques.','Repeat for the desired number of repetitions, then switch sides.']::text[], '9Tkqa9O'),
  ('db-0555', 'kick out sit', 'Legs', 'Body Weight', 'hamstrings', ARRAY['quadriceps','glutes']::text[], ARRAY['Sit on the edge of a bench or chair with your feet flat on the ground and your knees bent at a 90-degree angle.','Lean back slightly and place your hands on the edge of the bench or chair for support.','Engaging your hamstrings, lift your feet off the ground and extend your legs straight out in front of you.','Pause for a moment at the top, then slowly bend your knees and bring your feet back towards your body.','Repeat for the desired number of repetitions.']::text[], 'v7p5bYl'),
  ('db-0558', 'kipping muscle up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','triceps','shoulders','core']::text[], ARRAY['Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.','Engage your core and use a swinging motion to generate momentum.','As you swing forward, pull your chest towards the bar, using your lats and biceps to initiate the movement.','Continue the upward motion until your chest reaches the bar, then transition into a dip position by pushing down on the bar and extending your arms.','Lower yourself back down to the starting position by bending your arms and controlling the descent.','Repeat for the desired number of repetitions.']::text[], 'pM07UxU'),
  ('db-3640', 'knee touch crunch', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, lift your shoulder blades off the ground and reach your right hand towards your left knee.','Return to the starting position and repeat, this time reaching your left hand towards your right knee.','Continue alternating sides for the desired number of repetitions.']::text[], 'dTg95eZ'),
  ('db-1420', 'kneeling jump squat', 'Legs', 'Barbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start by kneeling on the ground with your feet hip-width apart and your toes pointing forward.','Hold a barbell across your upper back, resting it on your shoulders.','Engage your core and glutes, then explosively jump up into the air, extending your hips and knees.','As you jump, push through your toes and fully extend your ankles, knees, and hips.','Land softly back on the ground, bending your knees to absorb the impact.','Immediately go into the next repetition, repeating the jump squat motion.']::text[], 'UgDm3oy'),
  ('db-1346', 'kneeling lat stretch', 'Back', 'Body Weight', 'lats', ARRAY['shoulders','triceps']::text[], ARRAY['Kneel on the ground with your knees hip-width apart and your toes pointing back.','Extend your arms overhead and interlace your fingers.','Keeping your back straight, slowly lean to the right side, feeling a stretch in your left lat muscle.','Hold the stretch for 20-30 seconds, then return to the starting position.','Repeat the stretch on the left side, leaning to the left and feeling a stretch in your right lat muscle.','Continue alternating sides for the desired number of repetitions.']::text[], 'f38OEuO'),
  ('db-3239', 'kneeling plank tap shoulder (male)', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','triceps']::text[], ARRAY['Start in a kneeling position with your hands on the ground, shoulder-width apart.','Extend your legs behind you, resting on your toes, and lift your body into a plank position.','Keeping your core engaged and your hips stable, lift one hand off the ground and tap the opposite shoulder.','Return the hand to the ground and repeat with the other hand.','Continue alternating sides for the desired number of repetitions.']::text[], 'h1ezqSu'),
  ('db-3211', 'kneeling push-up (male)', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Start by kneeling on the ground with your hands shoulder-width apart, fingers pointing forward.','Extend your legs behind you, resting on the balls of your feet, so that your body forms a straight line from head to heels.','Engage your core and lower your body towards the ground by bending your elbows, keeping them close to your sides.','Continue lowering until your chest is just above the ground, then push back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'ZOuKWir'),
  ('db-3288', 'korean dips', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Position yourself between two parallel bars with your arms extended and supporting your body weight.','Lower your body by bending your elbows until your upper arms are parallel to the ground.','Pause for a moment, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'rWoBmi5'),
  ('db-3418', 'l-pull-up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.','Hang with your arms fully extended and your body straight.','Engage your lats and biceps to pull your body up towards the bar, keeping your elbows close to your body.','Continue pulling until your chin is above the bar.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'd1GgzTU'),
  ('db-3419', 'l-sit on floor', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Sit on the floor with your legs extended in front of you.','Place your hands on the floor beside your hips, fingers pointing forward.','Engage your core and lift your legs off the ground, keeping them straight.','Try to bring your legs parallel to the floor, forming an ''L'' shape with your body.','Hold this position for as long as you can.','Slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'UpWmA5E'),
  ('db-0562', 'landmine 180', 'Core', 'Barbell', 'abs', ARRAY['obliques','quadriceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the barbell with both hands in front of your chest.','Bend your knees slightly and rotate your torso to the right, swinging the barbell down towards your right hip.','As you reach the bottom of the movement, quickly reverse the motion and rotate your torso to the left, swinging the barbell up and across your body towards your left shoulder.','Continue this twisting motion, alternating sides, for the desired number of repetitions.']::text[], 'QYysSLV'),
  ('db-3237', 'landmine lateral raise', 'Shoulders', 'Barbell', 'delts', ARRAY['traps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Hold the barbell with an overhand grip, resting it on the front of your shoulders.','Keeping your core engaged and back straight, lift the barbell up and away from your body, raising it to shoulder height.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'eXMFHww'),
  ('db-3300', 'lean planche', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','chest','triceps']::text[], ARRAY['Start in a push-up position with your hands shoulder-width apart and your body straight.','Engage your core and slowly shift your weight forward, bringing your shoulders past your hands.','Keep your elbows slightly bent and your body straight as you lean forward.','Hold this position for a few seconds, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'LYJodFS'),
  ('db-2271', 'left hook. boxing', 'Shoulders', 'Body Weight', 'delts', ARRAY['biceps','triceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Keep your left hand up to protect your face and your right hand by your chin.','Rotate your hips and pivot on your left foot as you extend your left arm forward in a punching motion.','Twist your torso and engage your core muscles to generate power in the punch.','Snap your arm back to the starting position and repeat for the desired number of repetitions.']::text[], 'hoXt6wv'),
  ('db-0570', 'leg pull in flat bench', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Sit on a flat bench with your legs extended straight out in front of you.','Place your hands on the bench beside your hips for support.','Engage your abs and lift your legs off the ground, bringing your knees towards your chest.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OyoZ3Pu'),
  ('db-1576', 'leg up hamstring stretch', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes']::text[], ARRAY['Lie flat on your back with your legs extended.','Bend one knee and bring it towards your chest, holding onto your thigh or shin.','Straighten your leg as much as possible while keeping it elevated.','Hold the stretch for 20-30 seconds.','Repeat with the other leg.']::text[], 'sU5BrfP'),
  ('db-2287', 'lever alternate leg press', 'Legs', 'Leverage Machine', 'quads', ARRAY['hamstrings','glutes']::text[], ARRAY['Adjust the seat and foot platform of the leverage machine to your desired position.','Sit on the machine with your back against the backrest and your feet on the foot platform.','Place your hands on the handles or sides of the machine for stability.','Push one foot against the foot platform, extending your leg until it is almost fully straight.','Pause for a moment, then slowly bend your leg and return to the starting position.','Repeat with the other leg.','Continue alternating legs for the desired number of repetitions.']::text[], 'V07qpXy'),
  ('db-0571', 'lever alternating narrow grip seated row', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height and footplate position to ensure proper alignment.','Sit on the machine with your back straight and feet flat on the footplate.','Grasp the handles with a narrow grip, palms facing each other.','Keep your chest up and shoulders back throughout the exercise.','Pull one handle towards your torso while keeping the other handle stationary.','Squeeze your shoulder blades together at the end of the movement.','Slowly return the handle to the starting position and repeat with the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'w2oRpuH'),
  ('db-0572', 'lever assisted chin-up', 'Back', 'Leverage Machine', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the leverage machine to your desired resistance level.','Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart.','Hang with your arms fully extended, keeping your body straight.','Engage your back muscles and pull your body up towards the handles, leading with your chest.','Continue pulling until your chin is above the handles.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'MaMuGH6'),
  ('db-0573', 'lever back extension', 'Back', 'Leverage Machine', 'spine', ARRAY['glutes','hamstrings']::text[], ARRAY['Adjust the machine to fit your body size and range of motion.','Sit on the machine with your back against the pad and your feet secured.','Place your hands on the handles or grip bars.','Engage your core and slowly lean forward, allowing your back to round slightly.','Pause for a moment at the bottom position, feeling a stretch in your lower back.','Using your back muscles, slowly raise your torso back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'rUXfn3R'),
  ('db-0574', 'lever bent over row', 'Back', 'Barbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Bend forward at the hips, keeping your back straight and chest up.','Pull the barbell towards your lower chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'X3cqyXz'),
  ('db-3200', 'lever bent-over row with v-bar', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height and position yourself facing the machine.','Grasp the v-bar with an overhand grip, keeping your back straight and your knees slightly bent.','Pull the v-bar towards your abdomen, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly release the weight back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'LuBEORI'),
  ('db-0575', 'lever bicep curl', 'Arms', 'Leverage Machine', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back against the pad.','Grasp the handles with an underhand grip, palms facing up, and keep your elbows close to your sides.','Exhale and curl the handles upward, contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the handles back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'q6y3OhV'),
  ('db-2289', 'lever calf press', 'Legs', 'Leverage Machine', 'calves', ARRAY['hamstrings']::text[], ARRAY['Adjust the seat of the leverage machine so that your shoulders are aligned with the lever pad.','Place your toes on the lever pad, with your heels hanging off the edge.','Grasp the handles or side supports for stability.','Push the lever pad down by extending your ankles, contracting your calf muscles.','Pause for a moment at the bottom of the movement.','Slowly return to the starting position by allowing your heels to rise back up.','Repeat for the desired number of repetitions.']::text[], '7B4F5nZ'),
  ('db-0577', 'lever chest press', 'Chest', 'Leverage Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back flat against the pad.','Grasp the handles with an overhand grip and position your elbows at a 90-degree angle.','Push the handles forward until your arms are fully extended, exhaling during the movement.','Pause briefly at the end of the movement, then slowly return to the starting position, inhaling as you do so.','Repeat for the desired number of repetitions.']::text[], 'T0yTjgW'),
  ('db-0576', 'lever chest press', 'Chest', 'Leverage Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back flat against the pad.','Grasp the handles with an overhand grip and position your elbows at a 90-degree angle.','Push the handles forward until your arms are fully extended, exhaling during the movement.','Pause briefly at the end of the movement, then slowly return to the starting position, inhaling as you do so.','Repeat for the desired number of repetitions.']::text[], 'DOoWcnA'),
  ('db-0578', 'lever deadlift', 'Legs', 'Leverage Machine', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Adjust the seat height and foot platform to your desired position.','Sit on the machine with your back against the pad and your feet flat on the foot platform.','Grasp the handles or the sides of the seat for stability.','Engage your glutes and hamstrings, and push through your heels to lift the weight up.','Keep your back straight and avoid rounding your shoulders.','Extend your hips fully at the top of the movement, squeezing your glutes.','Lower the weight back down in a controlled manner, keeping tension on your glutes and hamstrings.','Repeat for the desired number of repetitions.']::text[], 'GUT8I22'),
  ('db-1300', 'lever decline chest press', 'Chest', 'Leverage Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the seat height and backrest of the leverage machine to a comfortable position.','Sit on the machine with your back against the backrest and your feet flat on the floor.','Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.','Push the handles forward and away from your body until your arms are fully extended.','Slowly lower the handles back towards your chest, keeping your elbows slightly bent.','Pause for a moment at the bottom, then push the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'vsVoPHt'),
  ('db-1253', 'lever donkey calf raise', 'Legs', 'Leverage Machine', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Adjust the leverage machine to the appropriate height for your body.','Position yourself facing the machine, with your toes on the foot platform and your heels hanging off the edge.','Place your hands on the handles or the support bars for stability.','Engage your calves and lift your heels as high as possible, using the balls of your feet.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'C9LuR4A'),
  ('db-0579', 'lever front pulldown', 'Back', 'Leverage Machine', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.','Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.','Sit upright with your chest lifted and your shoulders back, maintaining a slight arch in your lower back.','Engage your lats and pull the handles down towards your chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], '7F1DVzn'),
  ('db-0580', 'lever gripless shrug', 'Back', 'Leverage Machine', 'traps', ARRAY['shoulders','forearms']::text[], ARRAY['Adjust the seat height and position yourself on the leverage machine.','Grasp the handles with your palms facing inwards and your arms fully extended.','Keeping your back straight, exhale and elevate your shoulders as high as possible.','Hold the contraction for a brief moment, then inhale and slowly lower your shoulders back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'f91FwXG'),
  ('db-1439', 'lever gripless shrug v. 2', 'Back', 'Leverage Machine', 'traps', ARRAY['shoulders','forearms']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back against the pad.','Grasp the handles or bars with an overhand grip, keeping your arms straight.','Keeping your back straight, lift your shoulders up towards your ears as high as possible.','Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'cbuFJrn'),
  ('db-2288', 'lever gripper hands', 'Arms', 'Leverage Machine', 'forearms', ARRAY['biceps','triceps']::text[], ARRAY['Adjust the seat height and grip the handles of the leverage machine.','Keep your back straight and your feet flat on the ground.','Exhale and squeeze the handles, contracting your forearms.','Hold the contraction for a second, then slowly release and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'mKwcrHn'),
  ('db-1615', 'lever hammer grip preacher curl', 'Arms', 'Leverage Machine', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the seat height and position yourself on the leverage machine.','Place your upper arms on the preacher pad, ensuring your chest is pressed against it.','Grasp the handles with a hammer grip (palms facing each other).','Keeping your upper arms stationary, exhale and curl the handles towards your shoulders.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OAguZoG'),
  ('db-0581', 'lever high row', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','rear deltoids']::text[], ARRAY['Adjust the seat height and foot platform to a comfortable position.','Sit on the machine with your chest against the pad and your feet flat on the foot platform.','Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.','Keep your back straight and engage your core.','Pull the handles towards your body, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'nZZZy9m'),
  ('db-2286', 'lever hip extension v. 2', 'Legs', 'Leverage Machine', 'glutes', ARRAY['hamstrings']::text[], ARRAY['Adjust the machine to fit your body and sit on it with your back against the backrest.','Place your feet on the footrests and grip the handles for stability.','Engage your glutes and hamstrings, then push against the footrests to extend your hips and raise your legs backward.','Pause for a moment at the top, then slowly lower your legs back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OPqShYN'),
  ('db-2611', 'lever horizontal one leg press', 'Legs', 'Leverage Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the seat of the machine so that your knees are at a 90-degree angle when your feet are on the footplate.','Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate.','Place your hands on the handles or sides of the machine for stability.','Push the footplate away from your body by extending your leg, keeping your back against the backrest.','Pause for a moment at the fully extended position, then slowly bend your leg to return to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], '9KU9TYF'),
  ('db-1299', 'lever incline chest press', 'Chest', 'Leverage Machine', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Adjust the seat and backrest of the leverage machine to a comfortable position.','Sit on the machine with your back against the backrest and your feet flat on the floor.','Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.','Push the handles forward and away from your body until your arms are fully extended.','Pause for a moment, then slowly bend your elbows and lower the handles back towards your chest.','Repeat for the desired number of repetitions.']::text[], 'jHAnWmT'),
  ('db-1479', 'lever incline chest press v. 2', 'Chest', 'Leverage Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the seat height and backrest angle on the leverage machine to a comfortable position.','Sit on the machine with your back against the backrest and your feet flat on the floor.','Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.','Push the handles forward and away from your body until your arms are fully extended, but without locking your elbows.','Pause for a moment at the fully extended position, then slowly bend your elbows and lower the handles back towards your chest.','Repeat for the desired number of repetitions.']::text[], 'o17Jfkt'),
  ('db-0582', 'lever kneeling leg curl', 'Legs', 'Leverage Machine', 'hamstrings', ARRAY['glutes']::text[], ARRAY['Adjust the machine to fit your body and select the desired weight.','Kneel on the machine facing downwards, with your knees resting on the pad and your feet secured under the footpads.','Grasp the handles or the sides of the machine for stability.','Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees.','Pause for a moment at the top of the movement, squeezing your hamstrings.','Inhale and slowly lower your legs back to the starting position, fully extending your knees.','Repeat for the desired number of repetitions.']::text[], 'nnmCTLN'),
  ('db-0583', 'lever kneeling twist', 'Core', 'Leverage Machine', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your knees resting on the pads and your upper body facing forward.','Grasp the handles or the sides of the machine for stability.','Keeping your core engaged, twist your torso to one side as far as comfortably possible.','Pause for a moment, then slowly return to the starting position.','Repeat the twist to the opposite side.','Continue alternating sides for the desired number of repetitions.']::text[], 'sZOR9EV'),
  ('db-0584', 'lever lateral raise', 'Shoulders', 'Leverage Machine', 'delts', ARRAY['traps','upper back']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back against the pad.','Grasp the handles with an overhand grip and keep your arms straight.','Exhale and raise your arms out to the sides until they are parallel to the floor.','Pause for a moment at the top, then inhale and slowly lower your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'dRTfGZT'),
  ('db-0585', 'lever leg extension', 'Legs', 'Leverage Machine', 'quads', ARRAY['hamstrings']::text[], ARRAY['Adjust the seat height and backrest of the machine to fit your body.','Sit on the machine with your back against the backrest and your feet on the footpad.','Grasp the handles or sidebars for stability.','Extend your legs forward by straightening your knees, lifting the weight.','Pause for a moment at the top, then slowly lower the weight back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'my33uHU'),
  ('db-0586', 'lever lying leg curl', 'Legs', 'Leverage Machine', 'hamstrings', ARRAY['calves']::text[], ARRAY['Adjust the machine to fit your body and select the desired weight.','Lie face down on the machine with your legs straight and your heels against the padded lever.','Grasp the handles or the sides of the machine for stability.','Keeping your upper body stationary, exhale and curl your legs up as far as possible without lifting your hips off the pad.','Hold the contracted position for a brief pause as you squeeze your hamstrings.','Inhale and slowly lower the lever back to the starting position.','Repeat for the desired number of repetitions.']::text[], '17lJ1kr'),
  ('db-3195', 'lever lying two-one leg curl', 'Legs', 'Leverage Machine', 'hamstrings', ARRAY['glutes']::text[], ARRAY['Adjust the machine to fit your body and sit on it with your back against the backrest.','Place your legs on the lever pad, just above your ankles.','Grasp the handles on the sides of the machine for support.','Keeping your upper body still, exhale and curl your legs up towards your glutes.','Pause for a moment at the top, then inhale and slowly lower your legs back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'UXpKJoq'),
  ('db-0587', 'lever military press', 'Shoulders', 'Leverage Machine', 'delts', ARRAY['triceps','upper chest']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back against the backrest.','Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.','Push the handles upward until your arms are fully extended, but do not lock your elbows.','Pause for a moment at the top, then slowly lower the handles back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'CggQhII'),
  ('db-0588', 'lever narrow grip seated row', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height and footrests to ensure proper form.','Sit on the machine with your feet flat on the footrests and your knees slightly bent.','Grasp the handles with a narrow grip, palms facing each other.','Keep your back straight and lean slightly forward.','Pull the handles towards your torso, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement.','Slowly release the handles and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'IGjKj1v'),
  ('db-0589', 'lever one arm bent over row', 'Back', 'Barbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with an overhand grip.','Bend forward at the hips, keeping your back straight and your head up.','Let the barbell hang in front of you with your arms fully extended.','Pull the barbell up towards your chest, keeping your elbows close to your body.','Squeeze your shoulder blades together at the top of the movement.','Lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Fhdtwf3'),
  ('db-1356', 'lever one arm lateral high row', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Adjust the seat height and position yourself facing the machine.','Grasp the handle with one hand and keep your back straight.','Pull the handle towards your body, keeping your elbow close to your side.','Squeeze your back muscles at the top of the movement.','Slowly release the handle back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OIFMAp1'),
  ('db-1347', 'lever one arm lateral wide pulldown', 'Back', 'Leverage Machine', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.','Grasp the handle with an overhand grip and fully extend your arm, keeping a slight bend in your elbow.','Pull the handle down and across your body towards your opposite hip, squeezing your lat muscle at the bottom of the movement.','Slowly return the handle to the starting position, fully extending your arm.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'tTuZSDT'),
  ('db-0590', 'lever one arm shoulder press', 'Shoulders', 'Leverage Machine', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back against the pad.','Grasp the lever handle with one hand and position your elbow at a 90-degree angle.','Press the lever upward until your arm is fully extended overhead.','Pause for a moment at the top, then slowly lower the lever back down to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], '2KGnL6M'),
  ('db-0591', 'lever overhand triceps dip', 'Arms', 'Leverage Machine', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Adjust the machine to the appropriate height and secure your body in position.','Grasp the handles with an overhand grip and position your body so that your arms are fully extended.','Lower your body by bending your elbows, keeping your upper arms close to your sides.','Continue lowering until your upper arms are parallel to the floor.','Pause for a moment, then push yourself back up to the starting position by extending your elbows.','Repeat for the desired number of repetitions.']::text[], 'D5yqP2p'),
  ('db-0592', 'lever preacher curl', 'Arms', 'Leverage Machine', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the seat height and position yourself on the leverage machine.','Place your upper arms on the pad and grip the handles with an underhand grip.','Keep your back straight and your elbows positioned on the pad.','Exhale and curl your forearms towards your upper arms, contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'b6hQYMb'),
  ('db-1614', 'lever preacher curl v. 2', 'Arms', 'Leverage Machine', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your upper arms resting on the pad and your chest against the support.','Grasp the handles with an underhand grip, slightly wider than shoulder-width apart.','Keep your upper arms stationary and exhale as you curl the handles towards your shoulders, contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale as you slowly lower the handles back to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'ye84CTU'),
  ('db-2285', 'lever pullover', 'Back', 'Leverage Machine', 'lats', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the seat and handles of the leverage machine to a comfortable position.','Sit on the machine with your back against the pad and grasp the handles with an overhand grip.','Keep your arms slightly bent and your core engaged.','Slowly pull the handles towards your chest, squeezing your lats.','Pause for a moment at the peak contraction, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], '4U7iLb5'),
  ('db-2736', 'lever reverse grip lateral pulldown', 'Back', 'Leverage Machine', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.','Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.','Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back.','Pull the handles down towards your chest, leading with your elbows and squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ky8FLU8'),
  ('db-1616', 'lever reverse grip preacher curl', 'Arms', 'Leverage Machine', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the seat height and position yourself on the leverage machine.','Grasp the handles with an underhand grip, palms facing up.','Rest your upper arms on the preacher pad, ensuring your elbows are fully extended.','Keeping your upper arms stationary, exhale and curl the handles towards your shoulders.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the handles back to the starting position, fully extending your elbows.','Repeat for the desired number of repetitions.']::text[], 'kj3hy6W'),
  ('db-1348', 'lever reverse grip vertical row', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height and footplate position to ensure proper alignment.','Sit on the machine with your chest against the pad and your feet flat on the footplate.','Grasp the handles with an underhand grip, palms facing up.','Keep your back straight and engage your core.','Pull the handles towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZqNOWQ6'),
  ('db-0593', 'lever reverse hyperextension', 'Legs', 'Leverage Machine', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Adjust the leverage machine to fit your body and secure your feet in the foot pads.','Lie face down on the machine with your upper body hanging off the edge and your hips resting on the pad.','Cross your arms over your chest or place them behind your head.','Engage your glutes and hamstrings to lift your legs upward until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Krmb3cB'),
  ('db-1349', 'lever reverse t-bar row', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height and footplate position on the leverage machine.','Sit on the machine with your chest against the pad and your feet flat on the footplate.','Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.','Keep your back straight and engage your core.','Pull the handles towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'BgljGjd'),
  ('db-2315', 'lever rotary calf', 'Legs', 'Leverage Machine', 'calves', ARRAY['soleus','ankle stabilizers']::text[], ARRAY['Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate.','Place your toes on the footplate, with your heels hanging off the edge.','Grasp the handles or the sides of the machine for stability.','Push through the balls of your feet, raising your heels as high as possible.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'MrgP9L6'),
  ('db-2335', 'lever seated calf press', 'Legs', 'Leverage Machine', 'calves', ARRAY['soleus','hamstrings']::text[], ARRAY['Adjust the seat of the machine so that your shoulders are aligned with the lever pad.','Place your toes on the lower portion of the platform and position your knees under the lever pad.','Grasp the handles on the sides of the seat for stability.','Press the lever pad down by extending your ankles, lifting your heels as high as possible.','Pause for a moment at the top of the movement, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Ie9UGty'),
  ('db-0594', 'lever seated calf raise', 'Legs', 'Leverage Machine', 'calves', ARRAY['soleus','ankle stabilizers']::text[], ARRAY['Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate.','Place your toes on the footplate with your heels hanging off the edge.','Grasp the handles or the sides of the seat for stability.','Push through the balls of your feet to raise your heels as high as possible.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bOOdeyc'),
  ('db-1452', 'lever seated crunch', 'Core', 'Leverage Machine', 'abs', ARRAY['obliques']::text[], ARRAY['Sit on the leverage machine with your back against the pad and your feet flat on the floor.','Grasp the handles or place your hands on the side pads for support.','Engage your abs and slowly lean back, allowing the pad to move with you.','Once your upper body is at a 45-degree angle, contract your abs and crunch forward, bringing your chest towards your knees.','Pause for a moment at the top, then slowly release and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Wgaz7pm'),
  ('db-0595', 'lever seated crunch (chest pad)', 'Core', 'Leverage Machine', 'abs', ARRAY['obliques']::text[], ARRAY['Adjust the seat height and chest pad position according to your comfort.','Sit on the machine with your back against the chest pad and your feet flat on the floor.','Grasp the handles or side bars for stability.','Engage your abs and slowly lean back, allowing the chest pad to move with you.','Pause for a moment at the maximum contraction, feeling the tension in your abs.','Slowly return to the starting position by contracting your abs and pulling yourself back up.','Repeat for the desired number of repetitions.']::text[], 'ZnJHhMk'),
  ('db-3760', 'lever seated crunch v. 2', 'Core', 'Leverage Machine', 'abs', ARRAY['obliques','hip flexors']::text[], ARRAY['Sit on the leverage machine with your back against the pad and your feet secured under the footpads.','Place your hands on the handles or the sides of the seat for support.','Engage your abs and slowly crunch forward, bringing your chest towards your knees.','Pause for a moment at the top of the movement, squeezing your abs.','Slowly return to the starting position, allowing your back to round slightly.','Repeat for the desired number of repetitions.']::text[], 'eXFXCY0'),
  ('db-1451', 'lever seated dip', 'Arms', 'Leverage Machine', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Adjust the seat height so that your feet are flat on the ground and your knees are at a 90-degree angle.','Grasp the handles of the leverage machine with your palms facing down and your arms fully extended.','Slowly lower your body by bending your elbows until your upper arms are parallel to the ground.','Pause for a moment, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'BRImeP8'),
  ('db-0596', 'lever seated fly', 'Chest', 'Leverage Machine', 'pectorals', ARRAY['deltoids','trapezius']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back against the pad.','Grasp the handles with a pronated grip and keep your elbows slightly bent.','Exhale and push the handles forward, bringing them together in front of your chest.','Pause for a moment, squeezing your chest muscles.','Inhale and slowly return to the starting position, allowing your chest muscles to stretch.','Repeat for the desired number of repetitions.']::text[], 'v3xmPAR'),
  ('db-3759', 'lever seated good morning', 'Legs', 'Leverage Machine', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Adjust the seat height so that your hips are slightly higher than your knees.','Sit on the machine with your back against the pad and your feet flat on the footrests.','Grasp the handles or the sides of the seat for stability.','Keeping your back straight, slowly lean forward from your hips until your upper body is parallel to the ground.','Pause for a moment, then slowly return to the starting position by pushing through your glutes and hamstrings.','Repeat for the desired number of repetitions.']::text[], 'XsCcxCC'),
  ('db-0597', 'lever seated hip abduction', 'Legs', 'Leverage Machine', 'abductors', ARRAY['glutes','hamstrings']::text[], ARRAY['Adjust the seat height so that your knees are at a 90-degree angle.','Sit on the machine with your back against the backrest and your feet on the footrests.','Place your hands on the side handles for stability.','Engage your abductors and slowly push your legs apart, away from the midline of your body.','Pause for a moment at the end of the movement, then slowly bring your legs back together to the starting position.','Repeat for the desired number of repetitions.']::text[], 'CHpahtl'),
  ('db-0598', 'lever seated hip adduction', 'Legs', 'Leverage Machine', 'adductors', ARRAY['hamstrings','glutes']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back against the backrest.','Place your feet on the footrests and grasp the handles for stability.','Engage your adductor muscles and slowly bring your legs together, squeezing your inner thighs.','Pause for a moment at the peak contraction, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'oHsrypV'),
  ('db-0599', 'lever seated leg curl', 'Legs', 'Leverage Machine', 'hamstrings', ARRAY['calves']::text[], ARRAY['Adjust the machine to fit your body and sit on it with your back against the backrest.','Place your lower legs under the padded lever, just above your ankles.','Grasp the handles on the sides of the machine for support.','Keeping your upper legs stationary, exhale and curl your legs up as far as possible.','Hold the contracted position for a brief pause as you squeeze your hamstrings.','Inhale and slowly lower the lever back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Zg3XY7P'),
  ('db-0600', 'lever seated leg raise crunch', 'Core', 'Leverage Machine', 'abs', ARRAY['hip flexors']::text[], ARRAY['Sit on the leverage machine with your back against the backrest and your feet on the footrests.','Grasp the handles or sidebars for stability.','Engage your abs and slowly raise your legs up towards your chest, curling your torso forward at the same time.','Pause for a moment at the top, then slowly lower your legs and torso back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'PQ2AtC3'),
  ('db-0602', 'lever seated reverse fly', 'Shoulders', 'Leverage Machine', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.','Grasp the handles with an overhand grip and keep your arms slightly bent.','Exhale and squeeze your shoulder blades together as you pull the handles back and outward, away from your body.','Pause for a moment at the peak contraction, then inhale and slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'myfUsKf'),
  ('db-0601', 'lever seated reverse fly (parallel grip)', 'Shoulders', 'Leverage Machine', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.','Grasp the handles with a parallel grip, palms facing each other, and keep your arms slightly bent.','Exhale and squeeze your shoulder blades together as you pull the handles back and outward, away from your body.','Pause for a moment at the peak contraction, then inhale and slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'xiHiJcA'),
  ('db-1350', 'lever seated row', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height and footrests to a comfortable position.','Sit on the machine with your chest against the pad and your feet on the footrests.','Grasp the handles with an overhand grip, shoulder-width apart.','Keep your back straight and your core engaged.','Pull the handles towards your body, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement.','Slowly release the handles and return to the starting position.','Repeat for the desired number of repetitions.']::text[], '7I6LNUG'),
  ('db-1385', 'lever seated squat calf raise on leg press machine', 'Legs', 'Leverage Machine', 'calves', ARRAY['quadriceps','hamstrings','glutes']::text[], ARRAY['Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the footplate.','Sit on the machine with your back against the backrest and your feet flat on the footplate, shoulder-width apart.','Place your toes and the balls of your feet on the footplate, keeping your heels off the edge.','Release the safety handles and push the footplate away from you by extending your knees.','Once your knees are fully extended, slowly lower your heels by flexing your calves.','Pause for a moment at the bottom, then push the footplate back up by extending your calves.','Repeat for the desired number of repetitions.']::text[], 'IeDEXTe'),
  ('db-0603', 'lever shoulder press', 'Shoulders', 'Leverage Machine', 'delts', ARRAY['triceps','chest']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back against the backrest.','Grasp the handles with an overhand grip and position your hands at shoulder level.','Push the handles upward until your arms are fully extended, but do not lock your elbows.','Pause for a moment at the top, then slowly lower the handles back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '67n3r98'),
  ('db-0869', 'lever shoulder press v. 2', 'Shoulders', 'Leverage Machine', 'delts', ARRAY['triceps','chest']::text[], ARRAY['Adjust the seat height and backrest of the leverage machine to a comfortable position.','Sit on the machine with your back against the backrest and your feet flat on the floor.','Grasp the handles of the machine with an overhand grip, slightly wider than shoulder-width apart.','Push the handles upward and forward until your arms are fully extended, but not locked.','Pause for a moment at the top, then slowly lower the handles back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'vqsbmL0'),
  ('db-2318', 'lever shoulder press v. 3', 'Shoulders', 'Leverage Machine', 'delts', ARRAY['triceps','chest']::text[], ARRAY['Adjust the seat height and backrest of the leverage machine to a comfortable position.','Sit on the machine with your back against the backrest and your feet flat on the floor.','Grasp the handles of the machine with an overhand grip, slightly wider than shoulder-width apart.','Push the handles upward and forward until your arms are fully extended, but not locked.','Pause for a moment at the top, then slowly lower the handles back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'dNFYIU1'),
  ('db-0604', 'lever shrug', 'Back', 'Leverage Machine', 'traps', ARRAY['shoulders']::text[], ARRAY['Adjust the seat height and position yourself on the leverage machine with your back against the pad.','Grasp the handles with an overhand grip and keep your arms straight.','Keeping your back straight, lift your shoulders up towards your ears as high as possible.','Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZZKbeMw'),
  ('db-0605', 'lever standing calf raise', 'Legs', 'Leverage Machine', 'calves', ARRAY['soleus','ankle stabilizers']::text[], ARRAY['Adjust the machine to your height and stand with your feet shoulder-width apart.','Place your shoulders under the pads and hold onto the handles for stability.','Raise your heels as high as possible by extending your ankles.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ykUOVze'),
  ('db-3758', 'lever standing chest press', 'Chest', 'Leverage Machine', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your feet flat on the ground.','Grasp the handles with an overhand grip and position your hands at chest level.','Push the handles forward until your arms are fully extended, keeping your elbows slightly bent.','Pause for a moment, then slowly bring the handles back towards your chest, maintaining control throughout the movement.','Repeat for the desired number of repetitions.']::text[], 'WbNq5Xu'),
  ('db-0606', 'lever t bar row', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height and footplate position to ensure proper alignment.','Sit on the machine with your chest against the pad and your feet flat on the footplate.','Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.','Keep your back straight and engage your core.','Pull the handles towards your torso, squeezing your shoulder blades together.','Pause for a moment at the peak contraction, then slowly release the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'aaXr7ld'),
  ('db-1351', 'lever t-bar reverse grip row', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.','Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.','Keep your back straight and engage your core.','Pull the handles towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'FVM1AUZ'),
  ('db-0607', 'lever triceps extension', 'Arms', 'Leverage Machine', 'triceps', ARRAY['shoulders']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back against the pad.','Grasp the handles with an overhand grip and fully extend your arms in front of you.','Keeping your upper arms stationary, slowly lower the handles towards your forehead by bending your elbows.','Pause for a moment at the bottom, then push the handles back up to the starting position by extending your arms.','Repeat for the desired number of repetitions.']::text[], 'Ser9eQp'),
  ('db-1313', 'lever unilateral row', 'Back', 'Leverage Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height and position yourself facing the machine.','Grasp the handles with an overhand grip and keep your back straight.','Pull the handles towards your body, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement, then slowly release and extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'oROuvrX'),
  ('db-0609', 'london bridge', 'Back', 'Rope', 'upper back', ARRAY['shoulders','biceps','forearms']::text[], ARRAY['Attach the rope to a high anchor point.','Stand facing away from the anchor point with your feet shoulder-width apart.','Grasp the rope with an overhand grip, palms facing down.','Lean forward slightly, keeping your back straight and core engaged.','Pull the rope towards your body, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bLyQokI')
